// Build Anthropic API request with PDF as base64 document
const base64Item = $('PDF to Base64').first().json;
const pdfBase64 = base64Item.data;

if (!pdfBase64 || pdfBase64.length < 100) {
  throw new Error('No valid PDF data received. Length: ' + (pdfBase64 ? pdfBase64.length : 0));
}

const config = $('Configuration').first().json;

const requestBody = {
  model: config.anthropicModel || 'claude-sonnet-4-5-20250929',
  max_tokens: 1024,
  messages: [{
    role: 'user',
    content: [
      {
        type: 'document',
        source: {
          type: 'base64',
          media_type: 'application/pdf',
          data: pdfBase64
        }
      },
      {
        type: 'text',
        text: 'Extract the following fields from this invoice and return ONLY valid JSON, no markdown, no explanation:\n\n{\n  "vendor": "Name of the vendor/sender",\n  "invoice_number": "Invoice number",\n  "invoice_date": "YYYY-MM-DD",\n  "total_amount": 0.00,\n  "currency": "EUR",\n  "net_amount": 0.00,\n  "tax_rate": 19,\n  "tax_amount": 0.00\n}\n\nIf a field is not found, set it to null.'
      }
    ]
  }]
};

return [{ json: { requestBody } }];

// Parse and validate Claude AI response
const response = $input.first().json;

if (response.error) {
  throw new Error('Claude API error: ' + (response.error.message || JSON.stringify(response.error)));
}

const text = response.content?.[0]?.text || '';

let invoice;
try {
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  invoice = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Claude response is not valid JSON: ' + text.substring(0, 300));
}

// Validate required fields
const required = ['vendor', 'invoice_number', 'invoice_date', 'total_amount'];
const missing = required.filter(f => !invoice[f] && invoice[f] !== 0);
if (missing.length > 0) {
  throw new Error('Missing required fields: ' + missing.join(', '));
}

// Normalize numeric values
invoice.total_amount = parseFloat(invoice.total_amount);
invoice.net_amount = invoice.net_amount ? parseFloat(invoice.net_amount) : invoice.total_amount;
invoice.tax_amount = invoice.tax_amount ? parseFloat(invoice.tax_amount) : 0;
invoice.tax_rate = invoice.tax_rate ? parseFloat(invoice.tax_rate) : 0;
invoice.currency = invoice.currency || 'EUR';

return [{ json: invoice }];

// Verify Odoo auth and prepare duplicate check
const authResult = $input.first().json;
if (!authResult.result || authResult.error) {
  throw new Error('Odoo authentication failed: ' + JSON.stringify(authResult.error || 'uid is null'));
}

const uid = authResult.result;
const config = $('Configuration').first().json;
const invoice = $('Parse Extraction').first().json;

// Search for existing invoice with same reference number
const dupCheckBody = {
  jsonrpc: '2.0',
  method: 'call',
  params: {
    service: 'object',
    method: 'execute_kw',
    args: [
      config.odooDb,
      uid,
      config.odooPassword,
      'account.move',
      'search_read',
      [[['ref', '=', invoice.invoice_number], ['move_type', '=', 'in_invoice']]],
      { fields: ['id', 'ref', 'partner_id', 'state', 'amount_total'], limit: 1 }
    ]
  },
  id: 10
};

return [{ json: { uid, dupCheckBody, invoice } }];

// Duplicate found — return clean response
const dupResult = $('Search Duplicate Invoice').first().json.result[0];
const invoice = $('Prepare Duplicate Check').first().json.invoice;

return [{
  json: {
    success: false,
    duplicate: true,
    message: 'Invoice ' + invoice.invoice_number + ' already exists in Odoo.',
    existing_invoice: {
      odoo_id: dupResult.id,
      status: dupResult.state,
      amount: dupResult.amount_total,
      vendor: dupResult.partner_id ? dupResult.partner_id[1] : null
    },
    extracted_data: invoice
  }
}];

// No duplicate — prepare vendor search
const prev = $('Prepare Duplicate Check').first().json;
const config = $('Configuration').first().json;

const searchBody = {
  jsonrpc: '2.0',
  method: 'call',
  params: {
    service: 'object',
    method: 'execute_kw',
    args: [
      config.odooDb,
      prev.uid,
      config.odooPassword,
      'res.partner',
      'search_read',
      [[['name', 'ilike', prev.invoice.vendor], ['supplier_rank', '>', 0]]],
      { fields: ['id', 'name'], limit: 1 }
    ]
  },
  id: 2
};

return [{ json: { uid: prev.uid, searchBody, invoice: prev.invoice } }];

// Use existing vendor
const partnerId = $json.result[0].id;
const partnerName = $json.result[0].name;
const prev = $('Prepare Vendor Search').first().json;

return [{
  json: {
    partnerId,
    partnerName,
    uid: prev.uid,
    invoice: prev.invoice
  }
}];

// Vendor not found — prepare creation
const config = $('Configuration').first().json;
const prev = $('Prepare Vendor Search').first().json;

const createBody = {
  jsonrpc: '2.0',
  method: 'call',
  params: {
    service: 'object',
    method: 'execute_kw',
    args: [
      config.odooDb,
      prev.uid,
      config.odooPassword,
      'res.partner',
      'create',
      [{ name: prev.invoice.vendor, supplier_rank: 1, company_type: 'company' }]
    ]
  },
  id: 3
};

return [{ json: { createBody, uid: prev.uid, invoice: prev.invoice } }];

// Extract new vendor ID from create response
const result = $input.first().json;
if (!result.result) {
  throw new Error('Failed to create vendor: ' + JSON.stringify(result.error || result));
}

const prev = $('Prepare Create Vendor').first().json;

return [{
  json: {
    partnerId: result.result,
    partnerName: prev.invoice.vendor,
    uid: prev.uid,
    invoice: prev.invoice
  }
}];

// Prepare Odoo vendor bill (account.move)
const data = $input.first().json;
const config = $('Configuration').first().json;

const invoiceBody = {
  jsonrpc: '2.0',
  method: 'call',
  params: {
    service: 'object',
    method: 'execute_kw',
    args: [
      config.odooDb,
      data.uid,
      config.odooPassword,
      'account.move',
      'create',
      [{
        move_type: 'in_invoice',
        partner_id: data.partnerId,
        ref: data.invoice.invoice_number,
        invoice_date: data.invoice.invoice_date,
        invoice_line_ids: [
          [0, 0, {
            name: 'Invoice ' + data.invoice.invoice_number + ' - ' + data.invoice.vendor,
            quantity: 1,
            price_unit: data.invoice.net_amount
          }]
        ]
      }]
    ]
  },
  id: 4
};

return [{
  json: {
    invoiceBody,
    partnerId: data.partnerId,
    partnerName: data.partnerName,
    uid: data.uid,
    invoice: data.invoice
  }
}];

// Verify invoice creation and build success response
const result = $input.first().json;
if (!result.result) {
  throw new Error('Failed to create invoice: ' + JSON.stringify(result.error || result));
}

const prev = $('Prepare Invoice').first().json;

return [{
  json: {
    success: true,
    odoo_invoice_id: result.result,
    partner_id: prev.partnerId,
    partner_name: prev.partnerName,
    invoice: prev.invoice
  }
}];
